require "property.BaseProperty"
require "data.Area"

IceBlockProperty = class("IceBlockProperty", BaseProperty)

function IceBlockProperty:onPlayerEquip(player)
    if next(player.iceArea) == nil then
        player.iceArea = Area.new(player:getPosition(), 1)
        player.iceArea:setIceTime(self.config.duration)
    end
    player.canChangeIce = true
end

function IceBlockProperty:onPlayerUnload(player)
    player.canChangeIce = false
end

return IceBlockProperty